section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/csharp-entity-framework.json",
  "type": "object",
  "required": ["entity", "configuration", "repository", "migration"],
  "properties": {
    "entity": {
      "type": "object",
      "required": ["class_name", "has_public_setters", "data_annotations_present"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+$"},
        "has_public_setters": {"type": "boolean", "const": false},
        "data_annotations_present": {"type": "boolean", "const": false}
      }
    },
    "configuration": {
      "type": "object",
      "required": ["class_name", "configures_keys", "configures_indexes"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+Configuration$"},
        "configures_keys": {"type": "boolean", "const": true},
        "configures_indexes": {"type": "boolean"}
      }
    },
    "repository": {
      "type": "object",
      "required": ["class_name", "list_uses_asnotracking", "returns_iqueryable"],
      "properties": {
        "class_name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+Repository$"},
        "list_uses_asnotracking": {"type": "boolean", "const": true},
        "returns_iqueryable": {"type": "boolean", "const": false},
        "multi_collection_split_query": {"type": "boolean"}
      }
    },
    "migration": {
      "type": "object",
      "required": ["name", "appended"],
      "properties": {
        "name": {"type": "string", "pattern": "^[A-Z][A-Za-z0-9]+$"},
        "appended": {"type": "boolean", "const": true}
      }
    }
  }
}

example.code:
{
  "entity": {"class_name": "Order", "has_public_setters": false, "data_annotations_present": false},
  "configuration": {"class_name": "OrderConfiguration", "configures_keys": true, "configures_indexes": true},
  "repository": {"class_name": "OrderRepository", "list_uses_asnotracking": true, "returns_iqueryable": false, "multi_collection_split_query": true},
  "migration": {"name": "AddOrdersTable", "appended": true}
}

{
  "entity": {"class_name": "order", "has_public_setters": true, "data_annotations_present": true},
  "configuration": {"class_name": "OrderConfig", "configures_keys": false, "configures_indexes": false},
  "repository": {"class_name": "OrderRepo", "list_uses_asnotracking": false, "returns_iqueryable": true},
  "migration": {"name": "fix_typo", "appended": false}
}
